package format

import (
	"bytes"
	"fmt"
	"sort"
	"strings"

	"github.com/hashicorp/terraform/internal/addrs"
	"github.com/hashicorp/terraform/internal/plans"
	"github.com/hashicorp/terraform/internal/schemarepo"
)

// CompactDiffFormatter produces a condensed, summary-style diff output for
// terraform plan, showing only resource-level changes without attribute-level detail.
type CompactDiffFormatter struct{}

// Format returns a compact string representation of a plan's changes,
// grouped by action type and showing only resource-level information.
func (f *CompactDiffFormatter) Format(plan *plans.Plan, schemas *schemarepo.Schemas) string {
	if plan == nil || plan.Changes == nil {
		return ""
	}

	// Group resources by action
	resources := make(map[plans.Action][]*plans.ResourceInstanceChangeSrc)
	for _, rc := range plan.Changes.Resources {
		action := rc.Action
		resources[action] = append(resources[action], rc)
	}

	// Sort each action's resources
	for action := range resources {
		sort.Slice(resources[action], func(i, j int) bool {
			return resources[action][i].Addr.String() < resources[action][j].Addr.String()
		})
	}

	var buf bytes.Buffer

	// Define the order of actions to display
	actionOrder := []plans.Action{
		plans.Create,
		plans.Update,
		plans.Delete,
		plans.DeleteThenCreate,
		plans.CreateThenDelete,
		plans.Read,
		plans.NoOp,
	}

	// Output resources grouped by action
	for _, action := range actionOrder {
		if len(resources[action]) == 0 {
			continue
		}

		// Write action header with count
		actionSymbol := actionToSymbol(action)
		buf.WriteString(fmt.Sprintf("[%s] %s (%d)\n", actionSymbol, actionToLabel(action), len(resources[action])))

		// Write each resource
		for _, rc := range resources[action] {
			buf.WriteString(fmt.Sprintf("  %s.%s\n", rc.Addr.Resource.Resource.Type, rc.Addr.Resource.Resource.Name))

			// Add instance key if present
			if rc.Addr.Resource.Key != addrs.NoKey {
				buf.WriteString(fmt.Sprintf("    (instance: %s)\n", rc.Addr.Resource.Key.String()))
			}
		}
		buf.WriteString("\n")
	}

	// Write summary
	totalChanges := 0
	for _, action := range actionOrder {
		totalChanges += len(resources[action])
	}

	if totalChanges > 0 {
		buf.WriteString("Summary:\n")
		for _, action := range actionOrder {
			if len(resources[action]) > 0 {
				label := actionToLabel(action)
				count := len(resources[action])
				buf.WriteString(fmt.Sprintf("  %s: %d\n", label, count))
			}
		}
	}

	return buf.String()
}

// actionToLabel returns a human-readable label for an action.
func actionToLabel(action plans.Action) string {
	switch action {
	case plans.Create:
		return "Create"
	case plans.Update:
		return "Update"
	case plans.Delete:
		return "Delete"
	case plans.DeleteThenCreate:
		return "Replace (delete then create)"
	case plans.CreateThenDelete:
		return "Replace (create then delete)"
	case plans.CreateThenForget:
		return "Replace (create then forget)"
	case plans.Read:
		return "Read"
	case plans.Forget:
		return "Forget"
	case plans.NoOp:
		return "No-op"
	default:
		return "Unknown"
	}
}

// actionToSymbol returns a symbol representation for an action.
func actionToSymbol(action plans.Action) string {
	switch action {
	case plans.Create:
		return "+"
	case plans.Update:
		return "~"
	case plans.Delete:
		return "-"
	case plans.DeleteThenCreate:
		return "±"
	case plans.CreateThenDelete:
		return "∓"
	case plans.CreateThenForget:
		return "⨥"
	case plans.Read:
		return "<="
	case plans.Forget:
		return "."
	case plans.NoOp:
		return " "
	default:
		return "?"
	}
}

