func TestCompactDiffFormatter_WithInstanceKey(t *testing.T) {
	formatter := &CompactDiffFormatter{}
	changes := plans.NewChangesSrc()

	// Resource with count
	addr := addrs.RootModuleInstance.ResourceInstance(
		addrs.ManagedResourceMode,
		"aws_instance",
		"web",
		addrs.IntKey(0),
	)
	changes.Resources = append(changes.Resources, &plans.ResourceInstanceChangeSrc{
		Addr:        addr,
		PrevRunAddr: addr,
		ChangeSrc: plans.ChangeSrc{
			Action: plans.Create,
		},
	})

	// Resource with for_each
	addr2 := addrs.RootModuleInstance.ResourceInstance(
		addrs.ManagedResourceMode,
		"aws_instance",
		"web",
		addrs.StringKey("prod"),
	)
	changes.Resources = append(changes.Resources, &plans.ResourceInstanceChangeSrc{
		Addr:        addr2,
		PrevRunAddr: addr2,
		ChangeSrc: plans.ChangeSrc{
			Action: plans.Create,
		},
	})

	plan := &plans.Plan{
		Changes: changes,
	}
	schemas := &schemarepo.Schemas{}

	result := formatter.Format(plan, schemas)

	// Check for instance keys in output
	if !strings.Contains(result, "[0]") {
		t.Errorf("Expected [0] index in output, got: %q", result)
	}
	if !strings.Contains(result, "prod") {
		t.Errorf("Expected 'prod' key in output, got: %q", result)
	}
}

func TestCompactDiffFormatter_Sorted(t *testing.T) {
	formatter := &CompactDiffFormatter{}
	changes := plans.NewChangesSrc()

	// Add resources in non-alphabetical order
	addrs := []string{"z_resource", "a_resource", "m_resource"}
	for _, addrStr := range addrs {
		parts := strings.Split(addrStr, "_")
		addr := addrs.RootModuleInstance.ResourceInstance(
			addrs.ManagedResourceMode,
			parts[0]+"_type",
			parts[1],
			addrs.NoKey,
		)
		changes.Resources = append(changes.Resources, &plans.ResourceInstanceChangeSrc{
			Addr:        addr,
			PrevRunAddr: addr,
			ChangeSrc: plans.ChangeSrc{
				Action: plans.Create,
			},
		})
	}

	plan := &plans.Plan{
		Changes: changes,
	}
	schemas := &schemarepo.Schemas{}

	result := formatter.Format(plan, schemas)

	// Check that resources are sorted
	aIdx := strings.Index(result, "a_type.resource")
	mIdx := strings.Index(result, "m_type.resource")
	zIdx := strings.Index(result, "z_type.resource")

	if aIdx == -1 || mIdx == -1 || zIdx == -1 {
		t.Errorf("Not all resources found in output: %q", result)
	}

	if aIdx > mIdx || mIdx > zIdx {
		t.Errorf("Resources are not sorted correctly. a_idx=%d, m_idx=%d, z_idx=%d", aIdx, mIdx, zIdx)
	}
}

func TestCompactDiffFormatter_NoOpResources(t *testing.T) {
	formatter := &CompactDiffFormatter{}
	changes := plans.NewChangesSrc()

	// Add a create
	addr1 := addrs.RootModuleInstance.ResourceInstance(
		addrs.ManagedResourceMode,
		"aws_instance",
		"new",
		addrs.NoKey,
	)
	changes.Resources = append(changes.Resources, &plans.ResourceInstanceChangeSrc{
		Addr:        addr1,
		PrevRunAddr: addr1,
		ChangeSrc: plans.ChangeSrc{
			Action: plans.Create,
		},
	})

	// Add a no-op (should still appear in output for completeness)
	addr2 := addrs.RootModuleInstance.ResourceInstance(
		addrs.ManagedResourceMode,
		"aws_instance",
		"existing",
		addrs.NoKey,
	)
	changes.Resources = append(changes.Resources, &plans.ResourceInstanceChangeSrc{
		Addr:        addr2,
		PrevRunAddr: addr2,
		ChangeSrc: plans.ChangeSrc{
			Action: plans.NoOp,
		},
	})

	plan := &plans.Plan{
		Changes: changes,
	}
	schemas := &schemarepo.Schemas{}

	result := formatter.Format(plan, schemas)

	// Create should appear
	if !strings.Contains(result, "[+]") {
		t.Errorf("Expected create action in output, got: %q", result)
	}

	// No-op may or may not appear depending on implementation;
	// but the formatter should handle it gracefully
	if strings.Contains(result, "Error") {
		t.Errorf("Unexpected error in output: %q", result)
	}
}

func TestActionToLabel(t *testing.T) {
	tests := map[plans.Action]string{
		plans.Create:           "Create",
		plans.Update:           "Update",
		plans.Delete:           "Delete",
		plans.DeleteThenCreate: "Replace (delete then create)",
		plans.CreateThenDelete: "Replace (create then delete)",
		plans.CreateThenForget: "Replace (create then forget)",
		plans.Read:             "Read",
		plans.Forget:           "Forget",
		plans.NoOp:             "No-op",
	}

	for action, expectedLabel := range tests {
		label := actionToLabel(action)
		if label != expectedLabel {
			t.Errorf("actionToLabel(%v) = %q, want %q", action, label, expectedLabel)
		}
	}
}

func TestActionToSymbol(t *testing.T) {
	tests := map[plans.Action]string{
		plans.Create:           "+",
		plans.Update:           "~",
		plans.Delete:           "-",
		plans.DeleteThenCreate: "±",
		plans.CreateThenDelete: "∓",
		plans.CreateThenForget: "⨥",
		plans.Read:             "<=",
		plans.Forget:           ".",
		plans.NoOp:             " ",
	}

	for action, expectedSymbol := range tests {
		symbol := actionToSymbol(action)
		if symbol != expectedSymbol {
			t.Errorf("actionToSymbol(%v) = %q, want %q", action, symbol, expectedSymbol)
		}
	}
}

func TestCompactDiffFormatter_Comprehensive(t *testing.T) {
	formatter := &CompactDiffFormatter{}
	changes := plans.NewChangesSrc()

	// Create multiple resources with different actions
	resources := []struct {
		action plans.Action
		rtype  string
		name   string
	}{
		{plans.Create, "aws_instance", "web"},
		{plans.Create, "aws_instance", "app"},
		{plans.Update, "aws_security_group", "main"},
		{plans.Delete, "aws_instance", "old"},
		{plans.DeleteThenCreate, "aws_instance", "replaced"},
	}

	for _, res := range resources {
		addr := addrs.RootModuleInstance.ResourceInstance(
			addrs.ManagedResourceMode,
			res.rtype,
			res.name,
			addrs.NoKey,
		)
		changes.Resources = append(changes.Resources, &plans.ResourceInstanceChangeSrc{
			Addr:        addr,
			PrevRunAddr: addr,
			ChangeSrc: plans.ChangeSrc{
				Action: res.action,
			},
		})
	}

	plan := &plans.Plan{
		Changes: changes,
	}
	schemas := &schemarepo.Schemas{}

	result := formatter.Format(plan, schemas)

	// Verify structure
	expectedItems := []string{
		"[+]",
		"[~]",
		"[-]",
		"[±]",
		"Summary:",
		"Create: 2",
		"Update: 1",
		"Delete: 1",
		"Replace (delete then create): 1",
	}

	for _, item := range expectedItems {
		if !strings.Contains(result, item) {
			t.Errorf("Expected %q in output, got:\n%s", item, result)
		}
	}

	// Verify all resource addresses are present
	expectedAddrs := []string{
		"aws_instance.web",
		"aws_instance.app",
		"aws_security_group.main",
		"aws_instance.old",
		"aws_instance.replaced",
	}

	for _, addr := range expectedAddrs {
		if !strings.Contains(result, addr) {
			t.Errorf("Expected resource address %q in output, got:\n%s", addr, result)
		}
	}
}

func TestCompactDiffFormatter_Format(t *testing.T) {
	tests := []struct {
		name           string
		plan           *plans.Plan
		schemas        *schemarepo.Schemas
		expectedOutput string
	}{
		{
			name:           "nil plan",
			plan:           nil,
			schemas:        &schemarepo.Schemas{},
			expectedOutput: "",
		},
		{
			name: "empty changes",
			plan: &plans.Plan{
				Changes: plans.NewChangesSrc(),
			},
			schemas:        &schemarepo.Schemas{},
			expectedOutput: "",
		},
	}

	formatter := &CompactDiffFormatter{}

	for _, test := range tests {
		t.Run(test.name, func(t *testing.T) {
			result := formatter.Format(test.plan, test.schemas)
			if !cmp.Equal(result, test.expectedOutput) {
				t.Errorf("unexpected output:\n%s", cmp.Diff(test.expectedOutput, result))
			}
		})
	}
}

